import{_ as t,c as e,o as n,ag as o}from"./chunks/framework.GdcW6lnn.js";const A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/api-keys-description.md","filePath":"basics_api/api-keys-description.md"}'),i={name:"basics_api/api-keys-description.md"};function a(r,s,l,p,g,P){return n(),e("div",null,s[0]||(s[0]=[o(`<h3 id="🔑-api-keys-ключі-api-простии-спосіб-ідентифікаціі-додатків" tabindex="-1">🔑 API Keys (Ключі API): Простий спосіб ідентифікації додатків <a class="header-anchor" href="#🔑-api-keys-ключі-api-простии-спосіб-ідентифікаціі-додатків" aria-label="Permalink to “🔑 API Keys (Ключі API): Простий спосіб ідентифікації додатків”">​</a></h3><p><strong>Що це?</strong></p><p>API Key (ключ API) - це <strong>унікальний ідентифікатор</strong>, що видається клієнтській програмі (наприклад, веб-сайту, мобільному додатку, серверному застосунку) для її ідентифікації при зверненні до API. Це схоже на <strong>цифровий ключ</strong> 🔑, який дозволяє програмі отримати доступ до певних ресурсів або функціональності, що надаються API.</p><p><strong>Як це працює?</strong></p><ol><li><p><strong>Отримання ключа:</strong> Розробник реєструє свій додаток на платформі, що надає API, і отримує унікальний API Key. Цей процес часто включає створення облікового запису та реєстрацію нового &quot;додатку&quot; або &quot;проєкту&quot;.</p></li><li><p><strong>Передача ключа з кожним запитом:</strong> Клієнтська програма повинна включати цей API Key у кожен запит, який вона надсилає до API. Існує кілька поширених способів передачі ключа:</p><ul><li><strong>Заголовок HTTP (Custom Header):</strong> Часто використовується спеціальний HTTP-заголовок, такий як <code>X-API-Key</code>, <code>Authorization</code> (з певним префіксом) або інший, визначений розробником API.<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/resource HTTP/1.1</span></span>
<span class="line"><span>Host: api.example.com</span></span>
<span class="line"><span>X-API-Key: YOUR_API_KEY</span></span></code></pre></div></li><li><strong>Параметр запиту (Query Parameter):</strong> API Key може передаватися як параметр у URL-адресі запиту.<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/resource?api_key=YOUR_API_KEY HTTP/1.1</span></span>
<span class="line"><span>Host: api.example.com</span></span></code></pre></div></li><li><strong>Тіло запиту (Request Body):</strong> У деяких випадках (особливо для методів POST, PUT) API Key може передаватися як одне з полів у тілі запиту (наприклад, у форматі JSON).</li></ul></li><li><p><strong>Валідація ключа на сервері:</strong> Сервер API отримує запит і перевіряє наявність та валідність переданого API Key. Сервер порівнює отриманий ключ зі списком зареєстрованих та активних ключів.</p></li><li><p><strong>Авторизація (часто, але не завжди):</strong> Після успішної валідації ключа сервер може також перевірити, чи має цей конкретний ключ дозвіл на доступ до запитуваного ресурсу або виконання певної дії. Однак, API Key сам по собі в першу чергу є механізмом <strong>аутентифікації</strong> (ідентифікації програми), а не авторизації (визначення прав доступу).</p></li><li><p><strong>Надання доступу або відмова:</strong> Якщо API Key є валідним і (якщо застосовно) має необхідні дозволи, сервер обробляє запит і повертає відповідь. В іншому випадку сервер повертає помилку (зазвичай <code>401 Unauthorized</code> або <code>403 Forbidden</code>).</p></li></ol><p><strong>Переваги використання API Keys:</strong></p><ul><li><strong>Простота реалізації:</strong> API Keys відносно легко генерувати, передавати та перевіряти як на стороні клієнта, так і на стороні сервера.</li><li><strong>Швидка ідентифікація програми:</strong> Сервер може швидко ідентифікувати, яка програма робить запит.</li><li><strong>Обмеження використання (часто):</strong> API провайдери можуть використовувати API Keys для відстеження використання API кожним додатком та застосовувати обмеження на кількість запитів (rate limiting) на основі ключа.</li><li><strong>Просте відкликання доступу:</strong> У разі компрометації ключа, провайдер API може легко відкликати його, заблокувавши доступ для відповідного додатка.</li></ul><p><strong>Недоліки використання API Keys:</strong></p><ul><li><strong>Проблеми з безпекою:</strong><ul><li>API Keys є статичними секретами, і якщо вони потраплять до зловмисників (наприклад, будуть вбудовані в клієнтський код мобільного додатку або веб-сайту), це може призвести до несанкціонованого використання API.</li><li>Їх часто передають через HTTP-заголовки або параметри URL, що може бути небезпечно без використання HTTPS (TLS/SSL).</li></ul></li><li><strong>Обмежена ідентифікація користувача:</strong> API Key ідентифікує додаток, а не кінцевого користувача, який використовує цей додаток. Для ідентифікації користувачів потрібні інші механізми (наприклад, OAuth, JWT).</li><li><strong>Складність керування правами доступу на рівні користувача:</strong> API Keys зазвичай не підходять для складного керування правами доступу, що залежать від конкретного користувача.</li></ul><p><strong>Рекомендації щодо безпеки API Keys:</strong></p><ul><li><strong>Використовуйте HTTPS (TLS/SSL) завжди</strong>, щоб зашифрувати трафік і запобігти перехопленню API Keys.</li><li><strong>Зберігайте API Keys безпечно на стороні клієнта.</strong> Уникайте вбудовування їх безпосередньо в клієнтський код (особливо для мобільних додатків та веб-сайтів). Розгляньте використання безпечних сховищ або серверних проксі для обробки API-запитів.</li><li><strong>Регулярно переглядайте та оновлюйте API Keys.</strong></li><li><strong>Використовуйте різні API Keys для різних середовищ (розробка, тестування, продакшн).</strong></li><li><strong>Реалізуйте механізми відкликання API Keys у разі їх компрометації.</strong></li><li><strong>Розгляньте використання більш безпечних методів аутентифікації (наприклад, OAuth 2.0) для чутливих даних та складних сценаріїв авторизації.</strong></li></ul><p><strong>Висновок:</strong></p><p>API Keys є простим та ефективним способом ідентифікації додатків, що звертаються до API. Вони добре підходять для публічних API або API, де потрібна ідентифікація на рівні програми та обмеження використання. Однак, через свої обмеження в безпеці та ідентифікації користувачів, для більш складних сценаріїв та роботи з чутливими даними рекомендується використовувати більш надійні методи аутентифікації, такі як OAuth 2.0 або JWT.</p>`,13)]))}const d=t(i,[["render",a]]);export{A as __pageData,d as default};
